private struct TinderSwipeScreen: View {
    @State private var index = 0
    private let profiles = TinderDemoData.profiles
    var body: some View {
        ZStack {
            TinderTokens.tdrCanvas.ignoresSafeArea()
            VStack(spacing: 16) {
                HStack {
                    Image(systemName: "slider.horizontal.3").font(.title2)
                    Spacer()
                    Text("Tinder").font(.system(size: 22, weight: .bold)).foregroundStyle(TinderTokens.tdrPink)
                    Spacer()
                    Image(systemName: "bolt.fill").font(.title2).foregroundStyle(TinderTokens.tdrPink)
                }.padding(.horizontal)
                ZStack {
                    ForEach(Array(profiles.enumerated()), id: \.element.id) { i, profile in
                        if i >= index {
                            TinderSwipeCard(profile: profile, accent: TinderTokens.tdrPink)
                                .scaleEffect(i == index ? 1 : 0.96).offset(y: CGFloat(i - index) * 8)
                        }
                    }
                }.frame(maxHeight: 480)
                HStack(spacing: 24) {
                    TinderActionButton(icon: "xmark", color: .red, size: 56) { if index < profiles.count { index += 1 } }
                    TinderActionButton(icon: "star.fill", color: .blue, size: 48) {}
                    TinderActionButton(icon: "heart.fill", color: TinderTokens.tdrPink, size: 56) { if index < profiles.count { index += 1 } }
                }.padding(.bottom, 8)
            }
        }
    }
}

private struct TinderSwipeCard: View {
    let profile: TinderDatingProfile; let accent: Color
    var body: some View {
        ZStack(alignment: .bottomLeading) {
            RoundedRectangle(cornerRadius: 16).fill(profile.color.gradient).frame(maxWidth: .infinity).frame(height: 440)
            LinearGradient(colors: [.clear, .black.opacity(0.7)], startPoint: .center, endPoint: .bottom)
            VStack(alignment: .leading, spacing: 4) {
                HStack(alignment: .firstTextBaseline) {
                    Text(profile.name).font(.system(size: 28, weight: .bold)).foregroundStyle(.white)
                    Text("\(profile.age)").font(.system(size: 24)).foregroundStyle(.white)
                }
                Text(profile.bio).font(.system(size: 15)).foregroundStyle(.white.opacity(0.9))
            }.padding(20)
        }.padding(.horizontal, 12).shadow(color: .black.opacity(0.15), radius: 12, y: 6)
    }
}

private struct TinderActionButton: View {
    let icon: String; let color: Color; let size: CGFloat; let action: () -> Void
    var body: some View {
        Button(action: action) {
            Image(systemName: icon).font(.system(size: size * 0.35, weight: .bold)).foregroundStyle(color)
                .frame(width: size, height: size).background(Circle().fill(.white).shadow(color: .black.opacity(0.1), radius: 4, y: 2))
        }
    }
}

